body.script:
async function downloadVideo() {
    const url = document.getElementById('videoUrl').value;
    const btn = document.getElementById('btnText');
    const result = document.getElementById('result');
    const loading = document.getElementById('loading');

    if (!url) {
        alert("Masukin linknya dulu anjir!");
        return;
    }

    // Reset & Loading
    result.classList.add('hidden');
    loading.classList.remove('hidden');
    btn.disabled = true;

    try {
        // Kita pake API gratis dari Tikwm
        const response = await fetch(`https://www.tikwm.com/api/?url=${encodeURIComponent(url)}`);
        const data = await response.json();

        if (data.code === 0) {
            // Berhasil ambil data
            document.getElementById('thumb').src = "https://www.tikwm.com" + data.data.cover;
            document.getElementById('author').innerText = "@" + data.data.author.unique_id;
            document.getElementById('downloadLink').href = "https://www.tikwm.com" + data.data.play;

            result.classList.remove('hidden');
        } else {
            alert("Link salah atau video gak ketemu!");
        }
    } catch (err) {
        alert("Waduh, koneksi ke servernya lagi lemot!");
    } finally {
        loading.classList.add('hidden');
        btn.disabled = false;
    }
}
